import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { Location } from '../../core/models';

/**
 * Location create/edit form (manager only). Serves `locations/new` and
 * `locations/:id/edit`; presence of an :id switches to edit mode.
 */
@Component({
  selector: 'app-location-form',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './location-form.component.html',
  styleUrl: './location-form.component.css',
})
export class LocationFormComponent implements OnInit {
  readonly editId = signal<string | null>(null);
  readonly saving = signal(false);
  readonly error = signal<string | null>(null);

  readonly locations = signal<Location[]>([
    { id: 'l1', name: 'Main Warehouse', zone: 'A' },
    { id: 'l2', name: 'Storefront', zone: 'B' },
    { id: 'l3', name: 'Overflow Depot', zone: 'C' },
  ]);

  model = { name: '', zone: '' };

  constructor(
    private route: ActivatedRoute,
    private router: Router,
  ) {}

  get isEdit(): boolean {
    return this.editId() !== null;
  }

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    if (id) {
      this.editId.set(id);
      const existing = this.locations().find((l) => l.id === id);
      if (existing) {
        this.model = { name: existing.name, zone: existing.zone ?? '' };
      }
    }
  }

  submit(): void {
    if (!this.model.name) {
      this.error.set('Name is required.');
      return;
    }
    this.error.set(null);
    this.saving.set(true);
    this.router.navigate(['/locations']);
  }

  cancel(): void {
    this.router.navigate(['/locations']);
  }
}
